(function(){'use strict';const D=14,L=200,S='jf-new-arrival-style',C='jf-unified-badge-container';let ids=new Set(),initd=false;const iC=()=>{if(document.getElementById(S))return;const s=document.createElement('style');s.id=S;s.textContent=`.${C}{position:absolute;top:8px;left:8px;display:flex;flex-direction:column;gap:6px;z-index:11;pointer-events:none}.jf-badge-new{display:flex;align-items:center;gap:5px;padding:4px 10px!important;border-radius:6px!important;font-size:.75rem!important;font-weight:800!important;color:#fff;box-shadow:0 4px 10px rgba(0,0,0,.5)!important;backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);border:1px solid rgba(255,255,255,0.2)!important;text-transform:uppercase!important;letter-spacing:1px!important;line-height:1!important;background:linear-gradient(135deg,#10b981,#059669);width:fit-content;animation:jf-new-pulse 2s infinite}@keyframes jf-new-pulse{0%,100%{box-shadow:0 0 0 0 rgba(16,185,129,.6)}70%{box-shadow:0 0 0 6px rgba(16,185,129,0)}}`;document.head.appendChild(s)};const fN=async()=>{if(typeof ApiClient==='undefined')return;const u=ApiClient.getCurrentUserId();if(!u)return;try{const r=await ApiClient.getJSON(ApiClient.getUrl(`Users/${u}/Items`,{Recursive:true,IncludeItemTypes:'Movie,Series',SortBy:'DateCreated',SortOrder:'Descending',Limit:L,Fields:'DateCreated'}));if(r&&r.Items){const n=new Date(),ms=864e5;for(const i of r.Items){if(i.DateCreated){const d=Math.floor((n-new Date(i.DateCreated))/ms);if(d<=D)ids.add(i.Id);else break}}}}catch(e){}};const gC=(b)=>{let c=b.querySelector(`.${C}`);if(!c){c=document.createElement('div');c.className=C;b.appendChild(c)}return c};const pC=()=>{const cards=document.querySelectorAll('.card:not(.new-badge-processed)');cards.forEach(c=>{c.classList.add('new-badge-processed');const id=c.getAttribute('data-id');if(id&&ids.has(id)){const b=c.querySelector('.cardBox');if(!b)return;b.style.position='relative';const co=gC(b),bg=document.createElement('div');bg.className='jf-badge-new';bg.textContent='NEW';co.prepend(bg)}})};async function i(){if(typeof ApiClient==='undefined'||!ApiClient.getCurrentUserId())return;if(!initd){initd=true;iC();await fN()}pC()}const o=new MutationObserver(()=>{if(document.querySelector('.card:not(.new-badge-processed)'))i()});if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',()=>{o.observe(document.body,{childList:true,subtree:true});i()});else{o.observe(document.body,{childList:true,subtree:true});i()}})();
